package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class ExcluderTest {

  @Test
  void clone_shouldReturnDistinctButEqualInstance() {
    Excluder original = new Excluder();
    Excluder cloned = original.clone();

    assertNotNull(cloned);
    assertNotSame(original, cloned);

    // Check that fields are equal
    assertEquals(original.version, cloned.version);
    assertEquals(original.modifiers, cloned.modifiers);
    assertEquals(original.serializeInnerClasses, cloned.serializeInnerClasses);
    assertEquals(original.requireExpose, cloned.requireExpose);
    assertEquals(original.serializationStrategies, cloned.serializationStrategies);
    assertEquals(original.deserializationStrategies, cloned.deserializationStrategies);
  }

  @Test
  void clone_onCloneNotSupportedException_shouldThrowAssertionError() throws Exception {
    Excluder excluderSpy = Mockito.spy(new Excluder());

    // Use reflection to mock super.clone() throwing CloneNotSupportedException
    // Since clone() calls super.clone(), we need to create a subclass that overrides clone to throw
    class ExcluderSubclass extends Excluder {
      @Override
      protected Excluder clone() {
        try {
          throw new CloneNotSupportedException("forced");
        } catch (CloneNotSupportedException e) {
          throw new AssertionError(e);
        }
      }
    }

    ExcluderSubclass badExcluder = new ExcluderSubclass();

    AssertionError error = assertThrows(AssertionError.class, badExcluder::clone);
    assertTrue(error.getCause() instanceof CloneNotSupportedException);
    assertEquals("forced", error.getCause().getMessage());
  }
}

